#!/usr/bin/env node
// Bundle all tile_data/*.jsonc into tile_data.js for the HTML tools.
// Usage: node bundle_tiles.js

const fs = require("fs");
const path = require("path");

const SRC_DIR = path.join(__dirname, "tile_data");
const OUT_FILE = path.join(__dirname, "tile_data.js");

const { parseJSONC } = require("./jsonc.js");

const files = fs.readdirSync(SRC_DIR)
  .filter(f => f.endsWith(".jsonc"))
  .sort();

let allTiles = [];
let categories = [];

for (const f of files) {
  const src = fs.readFileSync(path.join(SRC_DIR, f), "utf-8");
  try {
    const tiles = parseJSONC(src);
    if (Array.isArray(tiles)) {
      allTiles = allTiles.concat(tiles);
      categories.push({ file: f, count: tiles.length });
    }
  } catch (e) {
    console.error("Error parsing", f, e.message);
    process.exit(1);
  }
}

// Verify no duplicate IDs
const ids = new Set();
for (const t of allTiles) {
  if (ids.has(t.id)) {
    console.error("Duplicate tile ID:", t.id);
    process.exit(1);
  }
  ids.add(t.id);
}

const output = `// Auto-generated by bundle_tiles.js — do not edit directly.
// Edit source files in tile_data/*.jsonc and re-run: node bundle_tiles.js

const TILE_DATA = ${JSON.stringify(allTiles, null, 2)};
`;

fs.writeFileSync(OUT_FILE, output, "utf-8");
console.log("Wrote", OUT_FILE);
console.log("Categories:");
for (const c of categories) {
  console.log("  " + c.file + " (" + c.count + " tiles)");
}
console.log("Total:", allTiles.length, "tiles");
